'use client';

import { useRouter, useSearchParams } from 'next/navigation';
import { useState } from 'react';
import { OfflineBanner } from '@/components/OfflineBanner';
import { getSession, setSession } from '@/lib/session';

export default function Page() {
  const [tableToken, setTableToken] = useState('');
  const router = useRouter();
  const search = useSearchParams();
  const error = search.get('error');
  const existing = getSession();

  return (
    <main>
      <OfflineBanner />
      <div className="card">
        <div className="hero">
          <h1>Pesan dari Meja</h1>
          <p className="small">Masukkan token QR meja untuk lihat menu.</p>
        </div>
        {error === 'token' ? (
          <p className="small" style={{ marginTop: 12 }}>
            Token meja tidak valid atau sudah berubah. Silakan scan ulang QR di meja.
          </p>
        ) : null}
        <input value={tableToken} onChange={(e) => setTableToken(e.target.value)} placeholder="table_token" />
        <div style={{ marginTop: 12 }}>
          <button onClick={() => router.push(`/menu?tableToken=${encodeURIComponent(tableToken)}`)}>Lihat Menu</button>
        </div>
        {existing?.tableToken ? (
          <div style={{ marginTop: 12 }}>
            <button
              className="secondary"
              onClick={() => {
                setSession(existing);
                router.push(`/menu?tableToken=${encodeURIComponent(existing.tableToken)}`);
              }}
            >
              Lanjutkan Meja Sebelumnya
            </button>
            {existing.lastOrderId ? (
              <div style={{ marginTop: 8 }}>
                <button
                  className="ghost"
                  onClick={() =>
                    router.push(
                      `/order-status?tableToken=${encodeURIComponent(existing.tableToken)}&orderId=${existing.lastOrderId}`,
                    )
                  }
                >
                  Lihat Order Terakhir #{existing.lastOrderId}
                </button>
              </div>
            ) : null}
          </div>
        ) : null}
      </div>
    </main>
  );
}
